async (page) => {
  for (let round = 0; round < 15; round++) {
    const rat = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s.nearby_entities.find(e => e.type === 3 && e.name === 'Rat' && e.on_screen && e.click_x != null);
    });

    if (!rat) {
      await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 180, y: 157});
      await page.waitForTimeout(3000);
      continue;
    }

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, { x: rat.click_x, y: rat.click_y });
    await page.waitForTimeout(8000);

    const s = await page.evaluate(() => {
      const g = window.__latestGameState;
      return { hp: g.player_stats.hp, max: g.player_stats.max_hp, lvl: g.player_stats.level };
    });
    console.log(`Round ${round}: lvl${s.lvl} hp${s.hp}/${s.max}`);

    if (s.hp < s.max * 0.35) {
      const bSlot = await page.evaluate(() => { const b = window.__latestGameState.inventory.find(i => i.edible); return b ? b.slot : -1; });
      if (bSlot >= 0) await page.evaluate((sl) => window.game.menu.getInventory().selectEdible(sl), bSlot);
    }
  }

  const final = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ hp: `${s.player_stats.hp}/${s.player_stats.max_hp}`, level: s.player_stats.level, pos: s.player_position });
  });
  return final;
}

