async (page) => {
  // Canvas click to walk adjacent and init dialogue
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 504, y: 336 });
  await page.waitForTimeout(3000);

  // Talk to Bike Lyson
  const bl = await page.evaluate(() => window.__latestGameState.nearby_entities.find(e => e.name === 'Bike Lyson'));
  const id = bl?.id || '1-3007126';

  const dialogues = [];
  for (let i = 0; i < 8; i++) {
    await page.evaluate((npcId) => window.__talkToNPC(npcId), id);
    await page.waitForTimeout(1000);
    const s = await page.evaluate(() => {
      const g = window.__latestGameState;
      const qp = document.getElementById('quest');
      return { d: g.ui_state.npc_dialogue, qp: qp ? window.getComputedStyle(qp).display !== 'none' : false };
    });
    console.log(`${i}: "${s.d}" qp=${s.qp}`);
    if (s.d) dialogues.push(s.d);
    if (s.qp) {
      await page.evaluate(() => document.getElementById('quest-button').click());
      await page.waitForTimeout(1000);
    }
    if (!s.d && i > 0) break;
  }

  return JSON.stringify({ dialogues, pos: await page.evaluate(() => `(${window.__latestGameState.player_position.x},${window.__latestGameState.player_position.y})`) });
}

