async (page) => {
  // Get VG instance ID from game entities
  const vgId = await page.evaluate(() => {
    try {
      // Try finding in game's entity list
      const entities = window.game && window.game.entities && window.game.entities.entities;
      if (entities) {
        for (const [id, entity] of Object.entries(entities)) {
          if (entity.name === 'Village Girl') {
            return {id: id, type: typeof entity, keys: Object.keys(entity).slice(0, 20)};
          }
        }
      }
      // Try renderer or world
      return {error: 'not found', entityKeys: entities ? Object.keys(entities).slice(0, 5) : 'no entities'};
    } catch(e) {
      return {error: e.message};
    }
  });
  return JSON.stringify(vgId);
}

